import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void basic() {
        assertArrayEquals(new int[]{1, 3, 6, 10}, new Solution().runningSum(new int[]{1, 2, 3, 4}));
    }

    @Test
    void ones() {
        assertArrayEquals(new int[]{1, 2, 3, 4, 5}, new Solution().runningSum(new int[]{1, 1, 1, 1, 1}));
    }

    @Test
    void single() {
        assertArrayEquals(new int[]{3}, new Solution().runningSum(new int[]{3}));
    }

    @Test
    void empty() {
        assertArrayEquals(new int[]{}, new Solution().runningSum(new int[]{}));
    }

    @Test
    void negatives() {
        assertArrayEquals(new int[]{-1, -3, 0, 4}, new Solution().runningSum(new int[]{-1, -2, 3, 4}));
    }
}
